import { useState } from "react";

export default function CouponInput() {
  const [code, setCode] = useState("");
  const [discount, setDiscount] = useState();
  const [error, setError] = useState();

  async function applyCoupon() {
    setError();
    setDiscount();
    const res = await fetch("/api/coupons/apply", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ code }),
    });
    if (!res.ok) {
      setError("Network error");
      return;
    }
    const data = await res.json();
    // API replies: { ok: true, discount: { percent: 15 } }
    //   on success
    //          OR { ok: false, error: "COUPON_EXPIRED" }
    //   on a business-logic rejection — still HTTP 200.
    setDiscount(data.discount.percent);   // ← crashes on rejection payloads
  }

  return (
    <div>
      <input value={code} onChange={e => setCode(e.target.value)} placeholder="Coupon code"/>
      <button onClick={applyCoupon}>Apply</button>
      {discount && <p>{discount}% off applied!</p>}
      {error && <p className="error">{error}</p>}
    </div>
  );
}

